class Solution {

public:

    long long rectangleArea(vector<vector<int>>& rectangles) {

        set<int> st;

        for (auto rec : rectangles) {

            st.insert(rec[1]);

            st.insert(rec[3]);

        }

        vector<int> y;

        for (auto co : st) {

            y.push_back(co);

        }

        map<int, int> mp;

        rep(i, sz(y)) {

            mp[y[i]] = i;

        }

        vector<vector<int>> seg(sz(y)-1, vector<int>(2, 0));

        for (auto rec : rectangles) {

            seg[mp[rec[1]]][0] += rec[0];

            seg[mp[rec[3]]][0] -= rec[0];

            seg[mp[rec[1]]][1] += rec[2];

            seg[mp[rec[3]]][1] -= rec[2];

        }

        ll res = 0;

        ll cur = 0;

        ll pre = 0;

        rep(i, sz(seg)) {

            cur += seg[i][0];

            res += cur * (y[i+1] - y[i]);

            pre = cur;

        }

        return res;

    }

};




