/*nまでの素数を列挙して配列に保持*/

vector<ll> Eratosthenes(ll n) {



	vector<ll> arr(n);

	for (ll i = 0; i < n; i++) {

		arr[i] = 1;

	}

	arr[0] = arr[1] = 0;

	for (ll i = 2; i < sqrt(n); i++) {

		if (arr[i]) {

			for (ll j = 0; i * (j + 2) < n; j++) {

				arr[i * (j + 2)] = 0;

			}

		}

	}

	return arr;

}



